/**
 * ContentPoolPage — Content pool displaying AI-analyzed content items.
 *
 * Features:
 * - Content card list: platform tag, content type, title, author, engagement data
 * - AI analysis status badge (已分析 / 待分析)
 * - AI analysis trigger button
 * - Platform and status filters
 */
import React, { useMemo, useState } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Grid,
  Chip,
  Stack,
  Alert,
  CircularProgress,
  Button,
  IconButton,
  Tooltip,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
} from '@mui/material';
import AnalyticsIcon from '@mui/icons-material/Analytics';
import VisibilityIcon from '@mui/icons-material/Visibility';
import ThumbUpIcon from '@mui/icons-material/ThumbUp';
import ChatBubbleIcon from '@mui/icons-material/ChatBubble';
import { useBrandStore } from '@/shared/stores/brandStore';
import { db } from '@/shared/db/db';
import { useLiveQuery } from 'dexie-react-hooks';
import type { Comment } from '@/shared/types/comment';

interface ContentItem {
  id: number;
  platform: string;
  author: string;
  content: string;
  likes: number;
  comments: number;
  views: number;
  isAnalyzed: boolean;
  videoId: string;
  tags: string[];
}

const ContentPoolPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);

  const comments = useLiveQuery(
    () =>
      currentBrandId
        ? db.comments.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([] as Comment[]),
    [currentBrandId],
  );

  const [platformFilter, setPlatformFilter] = useState<string>('all');
  const [analysisFilter, setAnalysisFilter] = useState<string>('all');

  // Convert comments to content items grouped by videoId
  const contentItems: ContentItem[] = useMemo(() => {
    if (!comments) return [];
    const videoMap = new Map<string, ContentItem>();
    comments.forEach((c) => {
      const vid = c.videoId || c.id.toString();
      const existing = videoMap.get(vid);
      if (existing) {
        existing.comments += 1;
        existing.likes += c.likes ?? 0;
        if (c.isAnalyzed) existing.isAnalyzed = true;
      } else {
        videoMap.set(vid, {
          id: c.id,
          platform: c.platform || '未知',
          author: c.author || c.userName || '匿名',
          content: c.content,
          likes: c.likes ?? 0,
          comments: 1,
          views: 0,
          isAnalyzed: c.isAnalyzed,
          videoId: vid,
          tags: c.labels ?? [],
        });
      }
    });
    return [...videoMap.values()];
  }, [comments]);

  const filtered = useMemo(() => {
    let items = contentItems;
    if (platformFilter !== 'all') {
      items = items.filter((i) => {
        const p = i.platform.toLowerCase();
        if (platformFilter === 'xhs') return p.includes('小红书') || p.includes('xhs');
        if (platformFilter === 'dy') return p.includes('抖音') || p.includes('douyin') || p.includes('dy');
        return true;
      });
    }
    if (analysisFilter === 'analyzed') {
      items = items.filter((i) => i.isAnalyzed);
    } else if (analysisFilter === 'pending') {
      items = items.filter((i) => !i.isAnalyzed);
    }
    return items;
  }, [contentItems, platformFilter, analysisFilter]);

  const getPlatformColor = (platform: string): 'error' | 'default' | 'primary' => {
    const p = platform.toLowerCase();
    if (p.includes('小红书') || p.includes('xhs')) return 'error';
    if (p.includes('抖音') || p.includes('douyin') || p.includes('dy')) return 'default';
    return 'primary';
  };

  const formatPlatform = (platform: string): string => {
    const p = platform.toLowerCase();
    if (p.includes('小红书') || p.includes('xhs')) return '📕 小红书';
    if (p.includes('抖音') || p.includes('douyin') || p.includes('dy')) return '🎵 抖音';
    if (p.includes('b站') || p.includes('bilibili')) return '📺 B站';
    return platform;
  };

  if (!currentBrandId) {
    return (
      <Box sx={{ p: 4, textAlign: 'center' }}>
        <Alert severity="info">请先在顶部选择一个品牌</Alert>
      </Box>
    );
  }

  return (
    <Box sx={{ p: 3 }}>
      <Typography variant="h5" fontWeight={700} gutterBottom>
        📦 内容池
      </Typography>
      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
        基于导入评论生成的内容素材库，标记 AI 分析状态
      </Typography>

      {/* Filters */}
      <Stack direction="row" spacing={2} sx={{ mb: 3 }} alignItems="center">
        <FormControl size="small" sx={{ minWidth: 140 }}>
          <InputLabel>平台</InputLabel>
          <Select
            value={platformFilter}
            label="平台"
            onChange={(e) => setPlatformFilter(e.target.value)}
          >
            <MenuItem value="all">全部平台</MenuItem>
            <MenuItem value="xhs">📕 小红书</MenuItem>
            <MenuItem value="dy">🎵 抖音</MenuItem>
          </Select>
        </FormControl>

        <FormControl size="small" sx={{ minWidth: 140 }}>
          <InputLabel>AI 分析</InputLabel>
          <Select
            value={analysisFilter}
            label="AI 分析"
            onChange={(e) => setAnalysisFilter(e.target.value)}
          >
            <MenuItem value="all">全部状态</MenuItem>
            <MenuItem value="analyzed">✅ 已分析</MenuItem>
            <MenuItem value="pending">⏳ 待分析</MenuItem>
          </Select>
        </FormControl>

        <Box sx={{ flexGrow: 1 }} />
        <Typography variant="body2" color="text.secondary">
          共 {filtered.length} 条内容
        </Typography>
      </Stack>

      {comments === undefined ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
          <CircularProgress />
        </Box>
      ) : filtered.length === 0 ? (
        <Box sx={{ textAlign: 'center', py: 8 }}>
          <Typography variant="h6" color="text.secondary" gutterBottom>
            暂无内容
          </Typography>
          <Typography variant="body2" color="text.disabled">
            请先导入评论数据
          </Typography>
        </Box>
      ) : (
        <Grid container spacing={2}>
          {filtered.map((item) => (
            <Grid item xs={12} sm={6} md={4} key={item.id}>
              <Card
                sx={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  border: '1px solid',
                  borderColor: 'divider',
                }}
              >
                <CardContent sx={{ flexGrow: 1 }}>
                  {/* Platform + Analysis status */}
                  <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 1 }}>
                    <Chip
                      label={formatPlatform(item.platform)}
                      size="small"
                      color={getPlatformColor(item.platform)}
                      variant="outlined"
                      sx={{ fontSize: 11 }}
                    />
                    <Chip
                      label={item.isAnalyzed ? '已分析' : '待分析'}
                      size="small"
                      color={item.isAnalyzed ? 'success' : 'warning'}
                      sx={{ fontSize: 11, ml: 'auto' }}
                    />
                  </Stack>

                  {/* Content preview */}
                  <Typography variant="body2" sx={{ mb: 1.5, lineHeight: 1.5 }}>
                    {item.content.length > 120
                      ? item.content.substring(0, 120) + '...'
                      : item.content}
                  </Typography>

                  {/* Author */}
                  <Typography variant="caption" color="text.secondary" sx={{ mb: 1, display: 'block' }}>
                    作者：{item.author}
                  </Typography>

                  {/* Tags */}
                  {item.tags.length > 0 && (
                    <Stack direction="row" spacing={0.5} sx={{ mb: 1 }} flexWrap="wrap" useFlexGap>
                      {item.tags.slice(0, 3).map((tag, i) => (
                        <Chip key={i} label={tag} size="small" variant="outlined" sx={{ fontSize: 10, height: 20 }} />
                      ))}
                    </Stack>
                  )}

                  {/* Engagement stats */}
                  <Stack direction="row" spacing={2}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                      <ThumbUpIcon sx={{ fontSize: 14, color: 'text.secondary' }} />
                      <Typography variant="caption" color="text.secondary">
                        {item.likes}
                      </Typography>
                    </Box>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                      <ChatBubbleIcon sx={{ fontSize: 14, color: 'text.secondary' }} />
                      <Typography variant="caption" color="text.secondary">
                        {item.comments}
                      </Typography>
                    </Box>
                  </Stack>
                </CardContent>

                {/* AI Analysis button */}
                <Box sx={{ px: 2, pb: 1.5, pt: 0 }}>
                  <Button
                    size="small"
                    fullWidth
                    variant={item.isAnalyzed ? 'outlined' : 'contained'}
                    startIcon={<AnalyticsIcon />}
                    disabled={item.isAnalyzed}
                  >
                    {item.isAnalyzed ? '已分析' : 'AI 分析'}
                  </Button>
                </Box>
              </Card>
            </Grid>
          ))}
        </Grid>
      )}
    </Box>
  );
};

export default ContentPoolPage;
